    // Map to store the sums and the pairs that form them.
    // Key: sum (a^3 + b^3)
    // Value: Set of pairs [a, b] that yield this sum
    const sumsMap = new Map();

    // We need a^3 + b^3 <= n, with 1 <= a <= b.
    // Since a >= 1, we need b^3 < n. Thus, b < n^(1/3).
    // Since n <= 10^9, n^(1/3) <= 1000. We can iterate up to 1000.
    const maxB = Math.floor(Math.cbrt(n));

    // Iterate through all possible values of b (the larger number)
    for (let b = 1; b <= maxB; b++) {
        // Iterate through all possible values of a (the smaller or equal number)
        // a must satisfy a <= b.
        // Also, a^3 + b^3 <= n, which means a^3 <= n - b^3.
        // a <= (n - b^3)^(1/3).
        const maxA = Math.min(b, Math.floor(Math.cbrt(n - b * b * b)));

        for (let a = 1; a <= maxA; a++) {
            const sum = a * a * a + b * b * b;

            if (sum > n) {
                // This check is technically redundant due to maxA calculation, 
                // but serves as a safeguard.
                continue;
            }

            if (!sumsMap.has(sum)) {
                sumsMap.set(sum, new Set());
