            // Store the pair (a, b)
            // Since we iterate with a <= b, the pair is canonical.
            sumsMap.get(sum).add(`${a},${b}`);
        }
    }

    const goodNumbers = [];

    // Check which sums have at least two different pairs.
    for (const [sum, pairsSet] of sumsMap.entries()) {
        if (pairsSet.size >= 2) {
